import UIKit
import Alamofire

class TradeViewController: UIViewController {
    
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    @IBOutlet weak var portfolioTableView: UITableView!
    
    var portfolio = [StockTransaction]()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        portfolioTableView.dataSource = self
        portfolioTableView.delegate = self
        
        buyButton.addTarget(self, action: #selector(buyAction), for: .touchUpInside)
        sellButton.addTarget(self, action: #selector(sellAction), for: .touchUpInside)
    }
    
    @objc func buyAction() {
        guard let stockSymbol = stockSymbolTextField.text,
              let quantityString = quantityTextField.text,
              let quantity = Int(quantityString) else {
            return
        }
        
        executeTrade(stockSymbol: stockSymbol, quantity: quantity, type: .buy)
    }
    
    @objc func sellAction() {
        guard let stockSymbol = stockSymbolTextField.text,
              let quantityString = quantityTextField.text,
              let quantity = Int(quantityString) else {
            return
        }
        
        executeTrade(stockSymbol: stockSymbol, quantity: quantity, type: .sell)
    }
    
    func executeTrade(stockSymbol: String, quantity: Int, type: TradeType) {
        let url = "https://api.example.com/trade"
        let parameters: [String: Any] = [
            "stockSymbol": stockSymbol,
            "quantity": quantity,
            "type": type.rawValue
        ]
        
        Alamofire.request(url, method: .post, parameters: parameters, encoding: JSONEncoding.default, headers: nil).responseJSON { response in
            switch response.result {
            case .success(let value):
                print("Trade executed successfully: \(value)")
                self.fetchPortfolio()
            case .failure(let error):
                print("Error executing trade: \(error.localizedDescription)")
            }
        }
    }
    
    func fetchPortfolio() {
        let url = "https://api.example.com/portfolio"
        
        Alamofire.request(url, method: .get, parameters: nil, encoding: JSONEncoding.default, headers: nil).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let portfolioData = value as? [[String: Any]] {
                    self.portfolio = portfolioData.map { StockTransaction(dictionary: $0) }
                    DispatchQueue.main.async {
                        self.portfolioTableView.reloadData()
                    }
                }
            case .failure(let error):
                print("Error fetching portfolio: \(error.localizedDescription)")
            }
        }
    }
}

extension TradeViewController: UITableViewDataSource, UITableViewDelegate {
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return portfolio.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "PortfolioCell", for: indexPath)
        
        let stockTransaction = portfolio[indexPath.row]
        cell.textLabel?.text = "\(stockTransaction.stockSymbol): \(stockTransaction.quantity)"
        
        return cell
    }
}

enum TradeType: String {
    case buy
    case sell
}

struct StockTransaction {
    var stockSymbol: String
    var quantity: Int
    
    init(dictionary: [String: Any]) {
        self.stockSymbol = dictionary["stockSymbol"] as! String
        self.quantity = dictionary["quantity"] as! Int
    }
}